class IndexCache:
    def __init__(self):
        self.cache = {}

    def get_cache(self, index_file):
        if index_file in self.cache:
            return self.cache[index_file]
        else:
            # Initialize a new cache for the index file
            self.cache[index_file] = {}
            return self.cache[index_file]

    def put(self, index_file, key, value):
        cache = self.get_cache(index_file)
        cache[key] = value

    def get(self, index_file, key):
        cache = self.get_cache(index_file)
        return cache.get(key)

    def delete(self, index_file, key):
        cache = self.get_cache(index_file)
        if key in cache:
            del cache[key]
