    if "%%a"=="Sleep" (
        set GUID=%%a
        goto found
    )
)

:found
:: Set the Wake On LAN option to enabled
powercfg -devicequery wake_from_any > wake_from_any.txt

:: Find the GUID of the device that supports Wake On LAN
for /f "tokens=*" %%a in (wake_from_any.txt) do (
    if "%%a"=="Wake From Any" (
        set WOL_DEVICE=%%a
        goto found_device
    )
)

:found_device
:: Enable Wake On LAN
powercfg -deviceenablewake WOL_DEVICE

:: Display a confirmation message
